'use client'

import type { BrandingData } from './OnboardingFlow'

interface Props {
  data: BrandingData
    communityName: string
      onChange: (patch: Partial<BrandingData>) => void
        onBack: () => void
          onNext: () => void
          }

          export default function Step3Branding({ data, communityName, onChange, onBack, onNext }: Props) {
            return (
                <div className="onboarding-step">
                      <div className="onboarding-step__header">
                              <h1 className="onboarding-step__title">Choose your colours</h1>
                                      <p className="onboarding-step__sub">These define the look of your community page.</p>
                                            </div>

                                                  <div className="branding-layout">
                                                          <div className="branding-controls">
                                                                    <div className="field-group">
                                                                                <label htmlFor="ob-primary-color" className="field-label">
                                                                                              Primary colour <span className="field-label--hint">(Ruby)</span>
                                                                                                          </label>
                                                                                                                      <div className="color-picker-row">
                                                                                                                                    <input
                                                                                                                                                    id="ob-primary-color" type="color" className="color-swatch-input"
                                                                                                                                                                    value={data.primaryColor}
                                                                                                                                                                                    onChange={(e) => onChange({ primaryColor: e.target.value })}
                                                                                                                                                                                                  />
                                                                                                                                                                                                                <input
                                                                                                                                                                                                                                type="text" className="field-input color-hex-input"
                                                                                                                                                                                                                                                value={data.primaryColor} maxLength={7}
                                                                                                                                                                                                                                                                onChange={(e) => {
                                                                                                                                                                                                                                                                                  const v = e.target.value
                                                                                                                                                                                                                                                                                                    if (/^#[0-9a-fA-F]{0,6}$/.test(v)) onChange({ primaryColor: v })
                                                                                                                                                                                                                                                                                                                    }}
                                                                                                                                                                                                                                                                                                                                  />
                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                          <p className="field-hint">Used for buttons, accents, and highlights.</p>
                                                                                                                                                                                                                                                                                                                                                                    </div>

                                                                                                                                                                                                                                                                                                                                                                              <div className="field-group">
                                                                                                                                                                                                                                                                                                                                                                                          <label htmlFor="ob-secondary-color" className="field-label">
                                                                                                                                                                                                                                                                                                                                                                                                        Secondary colour <span className="field-label--hint">(Blush)</span>
                                                                                                                                                                                                                                                                                                                                                                                                                    </label>
                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="color-picker-row">
                                                                                                                                                                                                                                                                                                                                                                                                                                              <input
                                                                                                                                                                                                                                                                                                                                                                                                                                                              id="ob-secondary-color" type="color" className="color-swatch-input"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                              value={data.secondaryColor}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              onChange={(e) => onChange({ secondaryColor: e.target.value })}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <input
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          type="text" className="field-input color-hex-input"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          value={data.secondaryColor} maxLength={7}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          onChange={(e) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const v = e.target.value
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              if (/^#[0-9a-fA-F]{0,6}$/.test(v)) onChange({ secondaryColor: v })
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <p className="field-hint">Used for backgrounds, badges, and tags.</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="branding-preview" aria-label="Colour preview">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <p className="branding-preview__label">Preview</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              className="branding-preview__card"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          style={{ '--preview-ruby': data.primaryColor, '--preview-blush': data.secondaryColor } as React.CSSProperties}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="branding-preview__header">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="branding-preview__avatar" style={{ background: data.primaryColor }} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <p className="branding-preview__community-name">{communityName || 'Your Community'}</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <p className="branding-preview__handle">@community</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="branding-preview__post-card" style={{ borderLeft: `3px solid ${data.primaryColor}` }}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <p className="branding-preview__post-text">Just dropped a new track!</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              className="branding-preview__tag"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              style={{ background: data.secondaryColor, color: data.primaryColor }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            New release
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <button
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                className="branding-preview__btn"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              style={{ background: data.primaryColor }}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            type="button" disabled
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      Follow
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="onboarding-step__actions">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <button type="button" className="btn-ghost" onClick={onBack}>Back</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <button type="button" className="btn-primary" onClick={onNext}>Continue</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            )
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }